package com.vidaysalud.veterinaria.citaservicio.controller;import com.vidaysalud.veterinaria.citaservicio.dto.*;import com.vidaysalud.veterinaria.citaservicio.service.CitaService;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.time.LocalDateTime;import java.util.*;@RestController @RequestMapping("/api/v1/citas") @RequiredArgsConstructor public class CitaController{private final CitaService s;@GetMapping public ResponseEntity<ApiResponse<List<CitaResponseDTO>>>l(){return ok("Citas obtenidas",s.listar());}@GetMapping("/{id}")public ResponseEntity<ApiResponse<CitaResponseDTO>>b(@PathVariable Integer id){return ok("Cita encontrada",s.buscar(id));}@GetMapping("/mascota/{id}")public ResponseEntity<ApiResponse<List<CitaResponseDTO>>>m(@PathVariable Integer id){return ok("Citas de mascota",s.porMascota(id));}@PostMapping public ResponseEntity<ApiResponse<CitaResponseDTO>>c(@Valid @RequestBody CitaRequestDTO d){return ResponseEntity.status(201).body(resp(HttpStatus.CREATED,"Cita creada",s.crear(d)));}@PutMapping("/{id}")public ResponseEntity<ApiResponse<CitaResponseDTO>>u(@PathVariable Integer id,@Valid @RequestBody CitaRequestDTO d){return ok("Cita actualizada",s.actualizar(id,d));}@PatchMapping("/{id}/estado")public ResponseEntity<ApiResponse<CitaResponseDTO>>e(@PathVariable Integer id,@Valid @RequestBody EstadoCitaRequestDTO d){return ok("Estado actualizado",s.estado(id,d.getEstado()));}@DeleteMapping("/{id}")public ResponseEntity<ApiResponse<Void>>d(@PathVariable Integer id){s.eliminar(id);return ok("Cita eliminada",null);}private<T>ResponseEntity<ApiResponse<T>>ok(String m,T d){return ResponseEntity.ok(resp(HttpStatus.OK,m,d));}private<T>ApiResponse<T>resp(HttpStatus h,String m,T d){return ApiResponse.<T>builder().timestamp(LocalDateTime.now()).status(h.value()).mensaje(m).data(d).build();}}